<?php
if (!defined('ABSPATH')) exit;
class VH360_Giving_Transactions { public static function create($data){ global $wpdb; $t=VH360_Giving_Database::get_transactions_table(); $now=current_time('mysql'); $row=wp_parse_args($data,array('status'=>'pending','gateway'=>'stripe','gateway_mode'=>'payment','source'=>'dashboard','anonymous'=>0,'created_at'=>$now,'updated_at'=>$now)); $wpdb->insert($t,$row); return $wpdb->insert_id; } public static function update($id,$data){ global $wpdb; $data['updated_at']=current_time('mysql'); return $wpdb->update(VH360_Giving_Database::get_transactions_table(),$data,array('id'=>absint($id))); } public static function get($id){ global $wpdb; $t=VH360_Giving_Database::get_transactions_table(); return $wpdb->get_row($wpdb->prepare("SELECT * FROM {$t} WHERE id=%d",$id)); } public static function for_user($user_id,$limit=50){ global $wpdb; $t=VH360_Giving_Database::get_transactions_table(); return $wpdb->get_results($wpdb->prepare("SELECT * FROM {$t} WHERE user_id=%d ORDER BY created_at DESC LIMIT %d",$user_id,$limit)); } public static function total($where='1=1'){ global $wpdb; $t=VH360_Giving_Database::get_transactions_table(); return (float)$wpdb->get_var("SELECT COALESCE(SUM(amount),0) FROM {$t} WHERE status='paid' AND {$where}"); } }
